// VPI usage pattern that triggers many scope instances
import "DPI-C" function void dpi_func(input int x);
logic [31:0] data;
initial dpi_func(data);

logic [7:0] counter = 0;
always @(posedge clk) begin
    counter <= counter + 1;
    $display("Scope: %m Count: %d", counter);
end
